type AddImageToShotWithoutPositionVariables = Omit<
  AddImageToShotVariables,
  'timelineFrame' | 'skipOptimistic'
>;

function withUnpositionedAddImageVariables(
  variables: AddImageToShotWithoutPositionVariables,
): AddImageToShotVariables {
  return {
    ...variables,
